if (document.body.id === "index") {
  buildHomepageTemplate(homepageContent);
}

function buildHomepageTemplate(content) {
  main.innerHTML = renderHomepage(content);
}

function renderHomepage(content) {
  return [
    '<section class="rdc-lab-sec rdc-lab-hero">',
    '  <div class="rdc-lab-hero-inner rdc-p-20">',
    '    <div class="rdc-lab-hero-text rdc-mw-800 rdc-m-iauto rdc-p-bl20 rdc-p-in20">',
    '      <h1 class="rdc-ta-cen">',
    '        <span class="rdc-fw-600 rdc-fs-50 rdc-ff-baij rdc-c-white-3">' +
      content.hero.headline.primary +
      "</span>",
    '        <br /><span class="rdc-c-pink rdc-fs-20 rdc-fw-600 rdc-ff-baij rdc-m-t20 rdc-d-flex rdc-jc-cen"><i>' +
      content.hero.headline.accent +
      "</i></span>",
    "      </h1>",
    '      <div class="rdc-mw-500 rdc-m-iauto rdc-p-in20">',
    '        <p class="rdc-ta-cen rdc-fs-24">' +
      content.hero.description +
      "</p>",
    "      </div>",
    "    </div>",
    "    " + renderButton(content.hero.cta),
    "  </div>",
    "",
    '  <div class="rlab-cols-main rdc-m-t20 rdc-mw-1200 rdc-m-iauto rdc-p-20">',
    '    <div class="rlab-cols-inner rdc-lab-border rdc-d-flex rdc-m-w-full rdc-m-fw-wrap">',
    content.hero.benefits.map(renderBenefitCard).join(""),
    "    </div>",
    "  </div>",
    "</section>",
    "",
    renderFeaturedGeneratorsSection(content.featured),
    "",
    '<section class="rdc-lab-sec rdc-lab-why rdc-bg-dark-4 rdc-m-b4r rdc-m-m-0">',
    '  <div class="rlab-cols-main rdc-c-white-1 rdc-p-20 rdc-mw-1600 rdc-m-iauto">',
    '    <div class="rlab-cols-inner rdc-d-flex rdc-m-fw-wrap rdc-p-30 rdc-bg-dark-5 rdc-lab-border rdc-of-hid" id="' +
      content.sections.why.containerId +
      '"></div>',
    "  </div>",
    "</section>",
    "",
    '<section class="rdc-lab-sec rdc-lab-easy">',
    '  <div class="rdc-lab-easy-inner rdc-mw-1600 rdc-m-iauto rdc-p-20" id="' +
      content.sections.easy.containerId +
      '"></div>',
    "</section>",
    "",
    '<section class="rdc-lab-sec rdc-lab-cta-v1 rdc-p-in20">',
    '  <div class="rdc-lab-cta-v1-inner rdc-jc-spb rdc-mw-1600 rdc-m-iauto rdc-fw-wrap rdc-p-20 rdc-d-flex rdc-bg-dark-5 rdc-lab-border" id="' +
      content.sections.cta.containerId +
      '"></div>',
    "</section>",
  ].join("\n");
}

function renderBenefitCard(card) {
  return [
    '      <div class="rlab-cols-col rdc-ta-cen rdc-p-20 rdc-w-25 rdc-m-w-half">',
    "        " + homepageIcons[card.iconKey],
    '        <p><b class="rdc-fw-600 rdc-fs-14 rdc-ff-baij">' +
      card.title +
      "</b></p>",
    '        <p class="rdc-c-white-2 rdc-fs-12 rdc-mw-150 rdc-m-iauto">' +
      card.description +
      "</p>",
    "      </div>",
  ].join("\n");
}

function renderFeaturedGeneratorsSection(featured = {}) {
  featured = { ...homepageContent.featured, ...featured };
  const shouldRenderFeaturedItems = featured.showFeaturedItems !== false;

  return [
    '<section class="rdc-lab-sec rdc-lab-featured rdc-mw-1600 rdc-m-iauto rdc-p-20">',
    '  <div class="rdc-lab-featured-inner rdc-p-bl4r rdc-m-p-bl10">',
    shouldRenderFeaturedItems
      ? '    <h2 class="rdc-m-b20">' + featured.title + "</h2>"
      : "",
    shouldRenderFeaturedItems
      ? '    <div class="rdc-lab-featured-items rdc-d-flex rdc-fw-wrap" id="' +
          featured.itemsContainerId +
          '"></div>'
      : "",
    "",
    '    <div class="rdc-mw-1800 rdc-m-iauto rdc-p-10">',
    '      <h3 class="rdc-p-5 rdc-fs-14">' + featured.popularTitle + "</h3>",
    '      <div class="rlab-cols-main rdc-lab-pop rdc-t-ofx-scr">',
    '        <div class="rlab-cols-inner rdc-d-flex rdc-t-w-fit rdc-t-fw-nwra" id="' +
      featured.popularContainerId +
      '"></div>',
    "      </div>",
    "    </div>",
    "",
    "    " + renderButton(featured.cta, "rdc-m-t20"),
    "  </div>",
    "</section>",
  ].join("\n");
}

window.renderRdcLabFeaturedGeneratorsSection = renderFeaturedGeneratorsSection;

function renderButton(button, extraClasses = "") {
  const classes = [
    "rdc-lab-btn",
    "rdc-lab-primary-btn",
    "rdc-br-4",
    "rdc-fs-14",
    extraClasses,
  ]
    .filter(Boolean)
    .join(" ");

  return (
    '<a class="' +
    classes +
    '" href="' +
    button.href +
    '">' +
    button.label +
    "</a>"
  );
}
